      new CustomEvent("lv-page", { detail: { page: this.page }, bubbles: true, composed: true })
    );
  }

  private onHeaderKeyDown(e: KeyboardEvent, col: DataTableColumn) {
    if (e.key === "Enter" || e.key === " ") {
