    .lv-toast__body { flex: 1; min-width: 0; }
    .lv-toast__heading { font-weight: 600; margin-bottom: var(--lv-space-1); }
    .lv-toast__dismiss {
      background: transparent;
      border: none;
      cursor: pointer;
      color: inherit;
      padding: 0;
      font-size: var(--lv-text-base);
      line-height: 1;
      opacity: 0.7;
      flex-shrink: 0;
