                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                stroke-linecap="round"
                stroke-linejoin="round"
              >
                ${unsafeSVG(body)}
              </svg></span
            >`
          : nothing}
        <slot></slot>
      </button>
    `;
  }
